package com.allthinkstars.framework.iot.ai.tools.annotated;

import com.allthinkstars.framework.iot.ai.config.AiProperties;
import com.allthinkstars.framework.iot.ai.tools.ToolResult;
import com.allthinkstars.framework.iot.ai.tools.integration.dify.DifyDatasetClient;
import com.allthinkstars.framework.iot.ai.tools.integration.dify.DifyDatasetClientException;
import com.allthinkstars.framework.iot.ai.tools.support.AiRunContext;
import com.allthinkstars.framework.iot.ai.tools.support.annotation.AiToolComponent;
import com.allthinkstars.framework.iot.ai.tools.support.annotation.AiToolDef;
import com.allthinkstars.framework.iot.ai.tools.support.annotation.AiToolParam;
import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.node.ArrayNode;
import com.fasterxml.jackson.databind.node.ObjectNode;
import lombok.RequiredArgsConstructor;

import java.util.List;
import java.util.Set;
import java.util.stream.Collectors;

@RequiredArgsConstructor
@AiToolComponent
public class AiKnowledgeTools {
    private final AiProperties aiProperties;
    private final DifyDatasetClient difyDatasetClient;
    private final ObjectMapper objectMapper;

    @AiToolDef(
        name = "knowledge.search",
        value = "Search Dify knowledge base and return relevant snippets with source references"
    )
    public ToolResult knowledge_search(
        @AiToolParam(
            name = "query",
            value = "检索问题或关键词。",
            required = true,
            title = "检索主题",
            examples = {"铸造工艺优化", "球铁孕育工艺参数", "连铸裂纹原因"}
        ) String query,
        @AiToolParam(
            name = "dataset_id",
            value = "知识库ID；可选，不传则使用后端默认配置。"
        ) String datasetId,
        AiRunContext ctx
    ) {
        AiProperties.Dify dify = aiProperties.getKb().getDify();
        if (!dify.isEnabled()) {
            return ToolResult.fail("tool_disabled", "知识库检索工具未启用");
        }
        if (normalizeText(query) == null) {
            return missingArg("query", datasetId);
        }
        String selectedDatasetId = selectDatasetId(datasetId, dify.getDefaultDatasetId());
        if (selectedDatasetId == null) {
            return ToolResult.fail("tool_config_invalid", "未配置默认dataset_id，且调用参数未提供dataset_id");
        }
        if (!isDatasetAllowed(selectedDatasetId, dify.getDatasetWhitelist())) {
            return ToolResult.fail("tool_args_invalid", "dataset_id不在允许范围: " + selectedDatasetId);
        }

        int selectedTopK = dify.getRetrievalTopK();
        String selectedSearchMethod = normalizeText(dify.getSearchMethod());
        if (selectedSearchMethod == null) {
            selectedSearchMethod = "semantic_search";
        }
        double selectedScoreThreshold = dify.getScoreThreshold();
        boolean selectedRerankingEnable = dify.isRerankingEnable();

        ObjectNode reqBody = objectMapper.createObjectNode();
        reqBody.put("query", query.trim());
        ObjectNode retrievalModel = reqBody.putObject("retrieval_model");
        retrievalModel.put("search_method", selectedSearchMethod);
        retrievalModel.put("reranking_enable", selectedRerankingEnable);
        retrievalModel.put("top_k", selectedTopK);
        // Dify 1.13+ requires this field when retrieval_model is provided.
        retrievalModel.put("score_threshold_enabled", true);
        retrievalModel.put("score_threshold", selectedScoreThreshold);

        long start = System.currentTimeMillis();
        JsonNode raw;
        try {
            raw = difyDatasetClient.retrieve(selectedDatasetId, reqBody);
        } catch (DifyDatasetClientException e) {
            Integer statusCode = e.getStatusCode();
            if (statusCode != null && (statusCode == 401 || statusCode == 403)) {
                return ToolResult.fail("tool_auth_error", "知识库服务鉴权失败");
            }
            if (statusCode != null && (statusCode == 429 || statusCode >= 500)) {
                return ToolResult.fail("tool_upstream_error", "知识库服务暂时不可用，请稍后重试");
            }
            return ToolResult.fail("tool_upstream_error", "知识库服务调用失败，请稍后重试");
        }
        long tookMs = System.currentTimeMillis() - start;

        ArrayNode records = raw != null && raw.has("records") && raw.get("records").isArray()
            ? (ArrayNode) raw.get("records")
            : objectMapper.createArrayNode();

        ObjectNode data = objectMapper.createObjectNode();
        data.put("query", query.trim());
        data.put("dataset_id", selectedDatasetId);
        data.put("top_k", selectedTopK);
        data.put("search_method", selectedSearchMethod);
        data.put("score_threshold", selectedScoreThreshold);
        data.put("reranking_enable", selectedRerankingEnable);
        data.put("took_ms", tookMs);
        data.put("hit_count", records.size());

        ArrayNode items = objectMapper.createArrayNode();
        for (JsonNode record : records) {
            if (record == null || record.isNull()) {
                continue;
            }
            ObjectNode item = objectMapper.createObjectNode();
            JsonNode segment = record.path("segment");
            String snippet = normalizeSnippet(segment.path("content").asText(""));
            item.put("snippet", snippet);
            item.put("score", safeDouble(record.path("score"), 0.0D));
            item.put("document_id", segment.path("document_id").asText(""));
            item.put("document_name", segment.path("document").path("name").asText(""));
            items.add(item);
        }
        data.set("items", items);

        String preview = "dataset_id=" + selectedDatasetId + ", hits=" + items.size() + ", took_ms=" + tookMs;
        return ToolResult.ok(preview, data);
    }

    private ToolResult missingArg(String missingField, String datasetId) {
        ObjectNode args = objectMapper.createObjectNode();
        args.putNull("query");
        if (datasetId == null) {
            args.putNull("dataset_id");
        } else {
            args.put("dataset_id", datasetId);
        }
        ObjectNode data = objectMapper.createObjectNode();
        data.put("missingField", missingField);
        data.set("args", args);
        return ToolResult.fail("tool_args_missing", "缺少必填参数: " + missingField, data);
    }

    private String selectDatasetId(String datasetId, String defaultDatasetId) {
        String selected = normalizeText(datasetId);
        if (selected != null) {
            return selected;
        }
        return normalizeText(defaultDatasetId);
    }

    private boolean isDatasetAllowed(String datasetId, List<String> whitelist) {
        if (whitelist == null || whitelist.isEmpty()) {
            return true;
        }
        Set<String> normalized = whitelist.stream()
            .map(this::normalizeText)
            .filter(s -> s != null)
            .collect(Collectors.toSet());
        if (normalized.isEmpty()) {
            return true;
        }
        return normalized.contains(datasetId);
    }

    private String normalizeText(String value) {
        if (value == null) {
            return null;
        }
        String cleaned = value.trim();
        return cleaned.isEmpty() ? null : cleaned;
    }

    private String normalizeSnippet(String content) {
        if (content == null) {
            return "";
        }
        String singleLine = content.replace('\n', ' ').replace('\r', ' ').replace('\t', ' ').trim();
        if (singleLine.length() <= 320) {
            return singleLine;
        }
        return singleLine.substring(0, 320) + "...";
    }

    private double safeDouble(JsonNode node, double fallback) {
        if (node == null || node.isNull()) {
            return fallback;
        }
        if (node.isNumber()) {
            return node.asDouble();
        }
        try {
            return Double.parseDouble(node.asText());
        } catch (Exception ignore) {
            return fallback;
        }
    }
}

