package com.allthinkstars.framework.iot.ai.tools.annotated;

import com.allthinkstars.framework.iot.ai.config.AiProperties;
import com.allthinkstars.framework.iot.ai.tools.ToolRegistry;
import com.allthinkstars.framework.iot.ai.tools.ToolResult;
import com.allthinkstars.framework.iot.ai.tools.integration.dify.DifyDatasetClient;
import com.allthinkstars.framework.iot.ai.tools.integration.dify.DifyDatasetClientException;
import com.allthinkstars.framework.iot.ai.tools.support.AiRunContext;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.node.ArrayNode;
import com.fasterxml.jackson.databind.node.ObjectNode;
import org.junit.Assert;
import org.junit.Before;
import org.junit.Test;
import org.junit.runner.RunWith;
import org.mockito.ArgumentCaptor;
import org.mockito.Mock;
import org.mockito.junit.MockitoJUnitRunner;

import java.util.Arrays;
import java.util.List;
import java.util.stream.Collectors;

import static org.mockito.ArgumentMatchers.any;
import static org.mockito.ArgumentMatchers.eq;
import static org.mockito.Mockito.verify;
import static org.mockito.Mockito.when;

@RunWith(MockitoJUnitRunner.class)
public class AiKnowledgeToolsTest {

    @Mock
    private DifyDatasetClient difyDatasetClient;

    private ObjectMapper objectMapper;
    private AiProperties props;
    private AiKnowledgeTools tools;

    @Before
    public void setUp() {
        this.objectMapper = new ObjectMapper();
        this.props = new AiProperties();
        this.props.getKb().getDify().setEnabled(true);
        this.props.getKb().getDify().setBaseUrl("https://example.com");
        this.props.getKb().getDify().setApiKey("dataset-token");
        this.props.getKb().getDify().setDefaultDatasetId("default-ds");
        this.props.getKb().getDify().setDatasetWhitelist(Arrays.asList("default-ds", "allowed-ds"));
        this.props.getKb().getDify().setRetrievalTopK(5);
        this.props.getKb().getDify().setSearchMethod("semantic_search");
        this.props.getKb().getDify().setScoreThreshold(0.3D);
        this.props.getKb().getDify().setRerankingEnable(false);
        this.tools = new AiKnowledgeTools(props, difyDatasetClient, objectMapper);
    }

    @Test
    public void knowledgeSearch_shouldCallDifyAndReturnNormalizedItems() {
        ObjectNode response = objectMapper.createObjectNode();
        ArrayNode records = response.putArray("records");
        ObjectNode record = records.addObject();
        record.put("score", 0.91D);
        ObjectNode segment = record.putObject("segment");
        segment.put("document_id", "doc-1");
        segment.put("content", "line1\nline2");
        segment.putObject("document").put("name", "文档A");

        when(difyDatasetClient.retrieve(eq("allowed-ds"), any(ObjectNode.class))).thenReturn(response);

        ToolResult result = tools.knowledge_search(
            "铸造工艺优化",
            "allowed-ds",
            new AiRunContext()
        );

        Assert.assertTrue(result.isOk());
        Assert.assertEquals(1, result.getData().path("items").size());
        Assert.assertEquals("doc-1", result.getData().path("items").get(0).path("document_id").asText());
        Assert.assertEquals("文档A", result.getData().path("items").get(0).path("document_name").asText());
        Assert.assertEquals("line1 line2", result.getData().path("items").get(0).path("snippet").asText());

        ArgumentCaptor<ObjectNode> bodyCaptor = ArgumentCaptor.forClass(ObjectNode.class);
        verify(difyDatasetClient).retrieve(eq("allowed-ds"), bodyCaptor.capture());
        ObjectNode body = bodyCaptor.getValue();
        Assert.assertEquals("铸造工艺优化", body.path("query").asText());
        Assert.assertEquals("semantic_search", body.path("retrieval_model").path("search_method").asText());
        Assert.assertEquals(5, body.path("retrieval_model").path("top_k").asInt());
        Assert.assertTrue(body.path("retrieval_model").path("score_threshold_enabled").asBoolean());
        Assert.assertEquals(0.3D, body.path("retrieval_model").path("score_threshold").asDouble(), 0.0001D);
        Assert.assertFalse(body.path("retrieval_model").path("reranking_enable").asBoolean());
    }

    @Test
    public void knowledgeSearch_shouldRejectDatasetOutsideWhitelist() {
        ToolResult result = tools.knowledge_search(
            "test",
            "not-allowed",
            new AiRunContext()
        );
        Assert.assertFalse(result.isOk());
        Assert.assertEquals("tool_args_invalid", result.getCode());
    }

    @Test
    public void knowledgeSearch_shouldMapAuthError() {
        when(difyDatasetClient.retrieve(eq("default-ds"), any(ObjectNode.class)))
            .thenThrow(new DifyDatasetClientException("unauthorized", 401));

        ToolResult result = tools.knowledge_search(
            "test",
            null,
            new AiRunContext()
        );

        Assert.assertFalse(result.isOk());
        Assert.assertEquals("tool_auth_error", result.getCode());
    }

    @Test
    public void toolRegistry_shouldOnlyExposeBusinessArgumentsForKnowledgeSearch() {
        ToolRegistry registry = new ToolRegistry();

        registry.registerAnnotatedBean(objectMapper, tools);

        ToolRegistry.ToolSpec spec = registry.listToolSpecs().stream()
            .filter(item -> "knowledge.search".equals(item.getName()))
            .findFirst()
            .orElseThrow(() -> new AssertionError("knowledge.search not registered"));

        List<String> paramNames = spec.getParameters().stream()
            .map(ToolRegistry.ToolParamSpec::getName)
            .collect(Collectors.toList());
        Assert.assertEquals(Arrays.asList("query", "dataset_id"), paramNames);
    }
}

