package com.allthinkstars.framework.iot.ai.tools.integration.dify;

import com.allthinkstars.framework.iot.ai.config.AiProperties;
import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.node.ObjectNode;
import lombok.extern.slf4j.Slf4j;
import org.springframework.http.HttpEntity;
import org.springframework.http.HttpHeaders;
import org.springframework.http.HttpMethod;
import org.springframework.http.MediaType;
import org.springframework.http.ResponseEntity;
import org.springframework.http.client.SimpleClientHttpRequestFactory;
import org.springframework.stereotype.Component;
import org.springframework.web.client.ResourceAccessException;
import org.springframework.web.client.RestClientResponseException;
import org.springframework.web.client.RestTemplate;

@Slf4j
@Component
public class DifyDatasetClient {

    private final AiProperties props;
    private final ObjectMapper objectMapper;
    private final RestTemplate restTemplate;

    public DifyDatasetClient(AiProperties props, ObjectMapper objectMapper) {
        this.props = props;
        this.objectMapper = objectMapper;

        SimpleClientHttpRequestFactory requestFactory = new SimpleClientHttpRequestFactory();
        AiProperties.Dify difyProps = props.getKb().getDify();
        requestFactory.setConnectTimeout(difyProps.getConnectTimeoutMs());
        requestFactory.setReadTimeout(difyProps.getReadTimeoutMs());
        this.restTemplate = new RestTemplate(requestFactory);
    }

    public JsonNode retrieve(String datasetId, ObjectNode requestBody) {
        String baseUrl = normalizeBaseUrl(props.getKb().getDify().getBaseUrl());
        String apiKey = normalizeText(props.getKb().getDify().getApiKey());
        if (baseUrl == null) {
            throw new DifyDatasetClientException("dify baseUrl未配置", null);
        }
        if (apiKey == null) {
            throw new DifyDatasetClientException("dify apiKey未配置", null);
        }
        if (normalizeText(datasetId) == null) {
            throw new DifyDatasetClientException("datasetId不能为空", null);
        }

        String url = baseUrl + "/v1/datasets/" + datasetId.trim() + "/retrieve";

        HttpHeaders headers = new HttpHeaders();
        headers.setContentType(MediaType.APPLICATION_JSON);
        headers.setAccept(java.util.Collections.singletonList(MediaType.APPLICATION_JSON));
        headers.setBearerAuth(apiKey);

        String body;
        try {
            body = objectMapper.writeValueAsString(requestBody == null ? objectMapper.createObjectNode() : requestBody);
        } catch (Exception e) {
            throw new DifyDatasetClientException("构造dify请求失败", null, e);
        }

        HttpEntity<String> entity = new HttpEntity<>(body, headers);
        try {
            ResponseEntity<String> response = restTemplate.exchange(url, HttpMethod.POST, entity, String.class);
            String responseBody = response.getBody();
            if (responseBody == null || responseBody.isBlank()) {
                throw new DifyDatasetClientException("dify返回空响应", response.getStatusCodeValue());
            }
            return objectMapper.readTree(responseBody);
        } catch (RestClientResponseException e) {
            String msg = "dify http error status=" + e.getRawStatusCode();
            throw new DifyDatasetClientException(msg, e.getRawStatusCode(), e);
        } catch (ResourceAccessException e) {
            throw new DifyDatasetClientException("dify连接超时或网络异常", null, e);
        } catch (DifyDatasetClientException e) {
            throw e;
        } catch (Exception e) {
            log.warn("dify retrieve failed datasetId={} error={}", datasetId, e.getMessage());
            throw new DifyDatasetClientException("dify调用失败", null, e);
        }
    }

    private String normalizeBaseUrl(String baseUrl) {
        String normalized = normalizeText(baseUrl);
        if (normalized == null) {
            return null;
        }
        if (normalized.endsWith("/")) {
            return normalized.substring(0, normalized.length() - 1);
        }
        return normalized;
    }

    private String normalizeText(String value) {
        if (value == null) {
            return null;
        }
        String normalized = value.trim();
        return normalized.isEmpty() ? null : normalized;
    }
}

