        if not normalized_api_base and _is_qwen_model(self._model):
            normalized_api_base = DEFAULT_DASHSCOPE_API_BASE
        self._api_base = normalized_api_base or None
        self._timeout_seconds = max(float(timeout_seconds), 1.0)

    @classmethod
    def from_env(cls, *, env: Mapping[str, str] | None = None) -> "LiteLLMProvider":
        source = os.environ if env is None else env
        api_key = str(source.get("LITELLM_API_KEY", "")).strip() or str(source.get("QWEN_API_KEY", "")).strip()
        key_file = str(source.get("QWEN_API_KEY_FILE", DEFAULT_QWEN_API_KEY_FILE)).strip() or DEFAULT_QWEN_API_KEY_FILE
        if not api_key:
            api_key = _read_api_key_from_file(key_file)
        model = (
            str(source.get("LLM_MODEL", "")).strip()
            or str(source.get("QWEN_MODEL", "")).strip()
            or DEFAULT_QWEN_MODEL
        )
        api_base = str(source.get("LITELLM_API_BASE", "")).strip() or str(source.get("QWEN_API_BASE", "")).strip()
        timeout_seconds = _parse_float(
            source.get("LITELLM_TIMEOUT_SECONDS") or source.get("QWEN_TIMEOUT_SECONDS"),
            default=DEFAULT_LITELLM_TIMEOUT_SECONDS,
            minimum=1.0,
        )
        return cls(
            api_key=api_key or None,
            model=model,
            api_base=api_base or None,
            timeout_seconds=timeout_seconds,
        )

    @property
    def available(self) -> bool:
        return bool(self._api_key)

    @property
    def model(self) -> str:
        return self._model

    async def invoke(
        self,
        *,
        conversation_id: str,
        mode: str,
        messages: list[dict[str, Any]],
        temperature: float,
    ) -> str:
        completion = await self.complete(
            conversation_id=conversation_id,
            mode=mode,
            messages=messages,
            temperature=temperature,
        )
        return completion.content

    async def complete(
        self,
        *,
        conversation_id: str,
        mode: str,
        messages: list[dict[str, Any]],
        temperature: float,
        tools: list[dict[str, Any]] | None = None,
    ) -> LLMCompletion:
        if not self.available:
            raise LLMProviderError(
                "LLM API key is not configured. Set LITELLM_API_KEY or QWEN_API_KEY, or provide QWEN_API_KEY_FILE."
            )
        kwargs: dict[str, Any] = {
            "model": self._model,
            "messages": messages,
            "temperature": temperature,
            "timeout": self._timeout_seconds,
            "api_key": self._api_key,
        }
        if self._api_base:
            kwargs["api_base"] = self._api_base
        if tools:
            kwargs["tools"] = tools
            kwargs["tool_choice"] = "auto"
        try:
            response = await acompletion(**kwargs)
        except Exception as exc:  # noqa: BLE001
            raise LLMProviderError(f"LiteLLM request failed: {exc}") from exc

        completion = _parse_completion_response(response)
        LOGGER.info(
            "llm_completion conversation_id=%s mode=%s model=%s tool_calls=%s output=%s",
            conversation_id,
            mode,
            self.model,
            [call.name for call in completion.tool_calls],
            truncate_text(completion.content, max_len=2000),
        )
        return completion


def _normalize_model_name(raw_model: str) -> str:
    model = (raw_model or "").strip() or DEFAULT_QWEN_MODEL
    if "/" in model:
        return model
    if model.startswith("qwen"):
        return f"openai/{model}"
    return model or DEFAULT_OPENAI_QWEN_MODEL


def _is_qwen_model(model: str) -> bool:
    normalized = (model or "").strip().lower()
    if "/" in normalized:
        normalized = normalized.split("/", 1)[1]
    return normalized.startswith("qwen")


def _read_api_key_from_file(path_value: str) -> str:
    resolved = path_value.strip() or DEFAULT_QWEN_API_KEY_FILE
    candidates = [Path(resolved)]
    if not Path(resolved).is_absolute():
        project_root = Path(__file__).resolve().parent.parent
        candidates.append(project_root / resolved)
    for path in candidates:
        if not path.exists() or not path.is_file():
            continue
        try:
            content = path.read_text(encoding="utf-8").strip()
        except OSError:
            continue
        if content:
            return content
    return ""


def _parse_float(raw_value: Any, *, default: float, minimum: float) -> float:
    try:
        parsed = float(raw_value)
    except (TypeError, ValueError):
        return default
    return max(parsed, minimum)


def _parse_completion_response(response: Any) -> LLMCompletion:
    try:
        message = response.choices[0].message
    except Exception as exc:  # noqa: BLE001
        raise LLMProviderError("LiteLLM response missing choices[0].message") from exc

    content = getattr(message, "content", "") or ""
    if isinstance(content, list):
        content = "\n".join(
            str(item.get("text") or "").strip()
            for item in content
            if isinstance(item, dict) and str(item.get("text") or "").strip()
        )
    if not isinstance(content, str):
        content = str(content)

    tool_calls: list[LLMToolCall] = []
    raw_tool_calls = getattr(message, "tool_calls", None) or []
    for item in raw_tool_calls:
        function = getattr(item, "function", None)
        name = str(getattr(function, "name", "") or "").strip()
        if not name:
            continue
        raw_arguments = getattr(function, "arguments", None)
        arguments = _parse_tool_arguments(raw_arguments)
        tool_calls.append(
            LLMToolCall(
                id=str(getattr(item, "id", "") or uuid4().hex),
                name=name,
                arguments=arguments,
            )
        )

    raw: dict[str, Any] = {}
    usage = getattr(response, "usage", None)
    if usage is not None:
        raw["usage"] = {
            "prompt_tokens": getattr(usage, "prompt_tokens", None),
            "completion_tokens": getattr(usage, "completion_tokens", None),
            "total_tokens": getattr(usage, "total_tokens", None),
        }
    return LLMCompletion(content=content.strip(), tool_calls=tool_calls, raw=raw)


def _parse_tool_arguments(raw_arguments: Any) -> dict[str, Any]:
    if isinstance(raw_arguments, dict):
        return dict(raw_arguments)
    if not isinstance(raw_arguments, str):
        return {}
    text = raw_arguments.strip()
    if not text:
        return {}
    try:
        payload = json.loads(text)
    except Exception:
        return {"raw": text}
    if isinstance(payload, dict):
        return payload
    return {"raw": payload}

